#include <stdio.h>
#include <stdbool.h>

bool isPositiveInt(long long x) {
    return x > 0;
}

unsigned long long factorial(long long n) {
    unsigned long long res = 1ULL;
    for (long long i = 2; i <= n; ++i) {
        res *= (unsigned long long)i;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        if (scanf("%lld", &n) != 1) break;
        if (!isPositiveInt(n)) {
            printf("-1\n");
        } else {
            printf("%llu\n", factorial(n));
        }
    }
    return 0;
}

